/// (`dumpVar(D,x)` expands to `dumpVector(D,&x,1)` expands to `dumpBlock(D,&x,sizeof(x))`)
fn dump_byte(&mut self, y: u8) -> Result<(), LuaError> {
    // C: lu_byte x = (lu_byte)y; dumpVar(D, x)
    self.dump_block(&[y])
}

